<template>
  <section class="character-stage">
    <CharacterStageBackground
      :key="stage.stageKey"
      :background-paths="staticBackgroundUrls"
      :background-overlays="staticBackgroundOverlayUrls"
      :fit-mode="backgroundFitMode"
    />

    <div class="character-stage__player">
      <SpineStageFrame
        v-if="!showFallback"
        :key="stage.stageKey"
        :entry="entry"
        :stage="stage"
        @failed="handleStageFailed"
      />
      <div v-else class="character-stage__fallback">
        <img
          v-if="fallbackImageUrl"
          :src="fallbackImageUrl"
          class="character-stage__fallback-image"
          :alt="entry.nameCn || entry.name"
        >
        <div v-else class="character-stage__fallback-text">当前立绘无法播放</div>
      </div>
    </div>

    <CharacterStageBackground
      :key="`${stage.stageKey}-foreground`"
      class="character-stage__foreground"
      :background-paths="staticBackgroundUrls"
      :background-overlays="staticForegroundOverlayUrls"
      :fit-mode="backgroundFitMode"
      :show-base="false"
    />

    <div v-if="showChrome" class="character-stage__panel">
      <div class="character-stage__nameplate">
        <div class="character-stage__name">{{ entry.nameCn || entry.name }}</div>
        <div class="character-stage__meta">{{ entry.cardId }} {{ stage.folder }}</div>
      </div>

      <div class="character-stage__variants" v-if="entry.stages.length > 1">
        <button
          v-for="(item, index) in entry.stages"
          :key="item.stageKey"
          type="button"
          class="character-stage__variant-button"
          :class="{ 'character-stage__variant-button--selected': index === internalStageIndex }"
          @click="handleStageSelected(index)"
        >
          立绘{{ index + 1 }}
        </button>
      </div>
    </div>
  </section>
</template>

<script>
import CharacterStageBackground from './CharacterStageBackground.vue';
import SpineStageFrame from './SpineStageFrame.vue';
import { toGalleryAssetUrl } from './assetPaths';
import { buildStageFitConfig } from './stageFitProfiles';

export default {
  name: 'CharacterStage',
  components: {
    CharacterStageBackground,
    SpineStageFrame,
  },
  props: {
    entry: {
      type: Object,
      required: true,
    },
    showChrome: {
      type: Boolean,
      default: true,
    },
    stageIndex: {
      type: Number,
      default: 0,
    },
  },
  emits: ['stage-selected'],
  data() {
    return {
      internalStageIndex: this.safeStageIndex(this.stageIndex),
      failedStageKeys: [],
      showFallback: false,
    };
  },
  computed: {
    stage() {
      if (!this.entry.stages.length) {
        return null;
      }
      const safeIndex = Math.min(
        Math.max(this.internalStageIndex, 0),
        this.entry.stages.length - 1,
      );
      return this.entry.stages[safeIndex];
    },
    fallbackImagePath() {
      if (!this.stage) {
        return this.entry.portraitPath || null;
      }
      return this.entry.portraitPath || this.stage.fallbackImagePath || null;
    },
    fallbackImageUrl() {
      return this.fallbackImagePath ? toGalleryAssetUrl(this.fallbackImagePath) : null;
    },
    backgroundFitMode() {
      if (!this.stage) {
        return 'cover';
      }
      return buildStageFitConfig(this.stage).backgroundFitMode || 'cover';
    },
    playerRenderedStaticPaths() {
      if (!this.stage) {
        return new Set();
      }

      const playerRenderedPaths = new Set();
      (this.stage.layers || []).forEach((layer) => {
        if (
          !layer ||
          (
            layer.isBackgroundLayer !== true &&
            layer.isStaticImageLayer !== true &&
            !layer.imagePath &&
            !layer.staticImagePath
          )
        ) {
          return;
        }
        [layer.imagePath, layer.staticImagePath].forEach((path) => {
          if (typeof path === 'string' && path) {
            playerRenderedPaths.add(path);
          }
        });
        (layer.backgroundTexturePaths || []).forEach((path) => {
          playerRenderedPaths.add(path);
        });
        (layer.texturePaths || []).forEach((path) => {
          playerRenderedPaths.add(path);
        });
      });

      return playerRenderedPaths;
    },
    staticBackgroundPaths() {
      if (!this.stage) {
        return [];
      }

      const playerRenderedPaths = this.playerRenderedStaticPaths;
      return (this.stage.backgroundPaths || []).filter((path) => (
        typeof path === 'string' && path && !playerRenderedPaths.has(path)
      ));
    },
    staticBackgroundUrls() {
      return this.staticBackgroundPaths.map((path) => toGalleryAssetUrl(path));
    },
    staticBackgroundOverlays() {
      if (!this.stage) {
        return [];
      }

      const playerRenderedPaths = this.playerRenderedStaticPaths;
      const overlays = this.stage.backgroundOverlayLayers || this.stage.backgroundOverlays || [];
      return overlays.filter((overlay) => (
        overlay &&
        typeof overlay.path === 'string' &&
        overlay.path &&
        !playerRenderedPaths.has(overlay.path)
      ));
    },
    staticBackgroundOverlayUrls() {
      return this.staticBackgroundOverlays.map((overlay) => ({
        ...overlay,
        path: toGalleryAssetUrl(overlay.path),
      }));
    },
    staticForegroundOverlays() {
      if (!this.stage) {
        return [];
      }

      const playerRenderedPaths = this.playerRenderedStaticPaths;
      const overlays = this.stage.foregroundOverlayLayers || this.stage.foregroundOverlays || [];
      return overlays.filter((overlay) => (
        overlay &&
        typeof overlay.path === 'string' &&
        overlay.path &&
        !playerRenderedPaths.has(overlay.path)
      ));
    },
    staticForegroundOverlayUrls() {
      return this.staticForegroundOverlays.map((overlay) => ({
        ...overlay,
        path: toGalleryAssetUrl(overlay.path),
      }));
    },
  },
  watch: {
    stageIndex(nextIndex) {
      this.internalStageIndex = this.safeStageIndex(nextIndex);
    },
    'entry.cardId'() {
      this.internalStageIndex = this.safeStageIndex(this.stageIndex);
      this.failedStageKeys = [];
      this.showFallback = false;
    },
  },
  methods: {
    safeStageIndex(index) {
      const stageCount = this.entry && Array.isArray(this.entry.stages)
        ? this.entry.stages.length
        : 0;
      if (!stageCount) {
        return 0;
      }
      const numericIndex = typeof index === 'number' && isFinite(index)
        ? Math.trunc(index)
        : 0;
      return Math.min(Math.max(numericIndex, 0), stageCount - 1);
    },
    handleStageSelected(index) {
      this.internalStageIndex = this.safeStageIndex(index);
      this.$emit('stage-selected', this.internalStageIndex);
      const nextStage = this.entry.stages[this.internalStageIndex];
      this.showFallback = Boolean(
        nextStage && this.failedStageKeys.includes(nextStage.stageKey),
      );
    },
    handleStageFailed(stageKey) {
      if (!stageKey || this.failedStageKeys.includes(stageKey)) {
        this.showFallback = true;
        return;
      }
      this.failedStageKeys = this.failedStageKeys.concat(stageKey);
      this.showFallback = true;
    },
  },
};
</script>

