const GALLERY_PREFIX_RE = /^\/?gallery-assets\//;

function trimSlashes(value) {
  return String(value || '').replace(/^\/+|\/+$/g, '');
}

function queryValue(name) {
  if (typeof window === 'undefined' || !window.location) {
    return '';
  }
  return new URLSearchParams(window.location.search).get(name) || '';
}

function configuredAssetRoot() {
  if (typeof window !== 'undefined') {
    const globalRoot = window.EDEN_GALLERY_ASSET_ROOT || window.__EDEN_GALLERY_ASSET_ROOT__;
    if (typeof globalRoot === 'string' && globalRoot.trim()) {
      return globalRoot.trim();
    }
  }

  const queryRoot = queryValue('assetRoot') || queryValue('assetBase');
  if (queryRoot) {
    return queryRoot;
  }

  const publicPath = process.env.BASE_URL || './';
  return `${publicPath.replace(/\/?$/, '/') }gallery-assets/`;
}

export function galleryAssetRoot() {
  const root = configuredAssetRoot();
  if (/^[a-z][a-z0-9+.-]*:/i.test(root)) {
    return root.replace(/\/?$/, '/');
  }
  return `${trimSlashes(root)}/`;
}

export function isGalleryAssetPath(value) {
  return typeof value === 'string' && GALLERY_PREFIX_RE.test(value);
}

export function toGalleryAssetUrl(value) {
  if (!isGalleryAssetPath(value)) {
    return value;
  }
  const rest = String(value).replace(GALLERY_PREFIX_RE, '');
  return `${galleryAssetRoot()}${rest}`;
}

export function toAbsoluteGalleryAssetUrl(value) {
  const url = toGalleryAssetUrl(value);
  if (typeof url !== 'string' || /^[a-z][a-z0-9+.-]*:/i.test(url)) {
    return url;
  }
  if (typeof window === 'undefined' || !window.location) {
    return url;
  }
  return new URL(url, window.location.href).href;
}

export function resolveGalleryAssetPaths(value, absolute = false) {
  const resolver = absolute ? toAbsoluteGalleryAssetUrl : toGalleryAssetUrl;
  if (Array.isArray(value)) {
    return value.map((item) => resolveGalleryAssetPaths(item, absolute));
  }
  if (value && typeof value === 'object') {
    return Object.keys(value).reduce((next, key) => {
      next[key] = resolveGalleryAssetPaths(value[key], absolute);
      return next;
    }, {});
  }
  return resolver(value);
}
