import {STAGE_FIT_BOUNDS} from './stageFitBounds.generated';

// 画廊适配的统一配置入口。
// 这里不去改 skeleton 本体的 scale，而是只给播放器一组"整体 viewport 缩放"参数。
// 这样能避免 Spine 各部件因为骨骼缩放出现比例失真。

const SHARED_VIEWPORT_SCALE = {
    // 允许页面极小比例继续显示。
    // 这里不能把最小值钳得太大，否则像 0.000001 这种整体缩放会被直接吞掉。
    min: 0.000001,
    // 不放大超过 1 倍，避免把原始纹理拉得太糊。
    max: 1.0,
};

const SHARED_CANVAS = {
    // 保持和 Flutter 版本一致的像素比上限。
    // 我们优先保证显示稳定，再去追更高的清晰度。
    maxPixelRatio: 2,
};

const DEFAULT_STAGE_DISPLAY_ADJUSTMENT = {
    scale: 1,
    displayAlign: 'center',
    offsetX: 0,
    offsetY: 0,
    responsive: true,
    referenceViewport: null,
};

// 手工微调配置默认以这个横屏尺寸作为参照。
// 例如你在 1396 x 765 下调出了 offsetX/offsetY，播放器会把它换算成
// 当前屏幕下等比例的屏幕偏移，避免切到 932 x 430 后位置跑偏。
const DEFAULT_DISPLAY_REFERENCE_VIEWPORT = {
    width: 1396,
    height: 765,
};

// 单个立绘的展示修正配置。
// key 优先推荐用 stage.folder，例如 '11301005_3'。
// scale 只会乘到 viewport initial-scale 上，不会修改 skeleton.scaleX / scaleY。
// displayAlign 可以写 center / top / bottom / left / right / topLeft / topRight /
// bottomLeft / bottomRight，默认 center。
// offsetX / offsetY 是在 referenceViewport 下调出来的 Spine 世界坐标偏移，
// 播放器会按当前 viewport 自动折算，默认 0,0 即保持原位置。
// 如果某个配置确实要固定世界坐标，不随屏幕变化，可以加 responsive: false。
export const STAGE_DISPLAY_ADJUSTMENTS = {
    '11300081_3': {scale: 1.1, offsetX: 0, offsetY: 0},
    '11300011_3': {scale: 1.0, offsetX: 0, offsetY: -100, displayAlign: 'bottom'},
    '11300009_3': {scale: 1.0, offsetX: 0, offsetY: 0},
    '11300004_3': {scale: 1.0, offsetX: -290, offsetY: -450, displayAlign: 'bottom'},
    '11202027_3': {scale: 1.0, offsetX: 0, offsetY: 0},
    '11202018_3': {scale: 1.3, offsetX: 0, offsetY: 0, displayAlign: 'bottom'},
    '11202017': {scale: 1.2, offsetX: 0, offsetY: 0},
    '11202009_3': {scale: 1.2, offsetX: 0, offsetY: 0, displayAlign: 'bottom'},
    '11201008_3': {scale: 0.8, offsetX: 0, offsetY: 0},
    '11200012_3': {scale: 1.4, offsetX: 0, offsetY: -300},
    '11200011': {scale: 1, offsetX: 0, offsetY: 0},
    '11200011_3': {scale: 1.1, offsetX: 0, offsetY: 0},
    '11200010_3': {scale: 1.1, offsetX: 0, offsetY: 0},
    '11200005_3': {scale: 0.7, offsetX: 0, offsetY: 0, displayAlign: 'top'},
    '11200002_3': {scale: 1.2, offsetX: 0, offsetY: 0},
    '11200001_3': {scale: 0.9, offsetX: 0, offsetY: 0, displayAlign: 'top'},
    '11101003_3': {scale: 0.7, offsetX: 0, offsetY: 0},
    '11101001_3': {scale: 1, offsetX: 0, offsetY: 0, displayAlign: 'top'},
    '11100001_3': {scale: 0.8, offsetX: 0, offsetY: 0, displayAlign: 'top'},






};

export const STAGE_FIT_PROFILES = {
    character: {
        key: 'character',
        // 普通人物立绘：优先让全身完整可见，同时给底部人物条留一点余量。
        visibleWidthRatio: 1.0,
        visibleHeightRatio: 0.92,
        backgroundFitMode: 'cover',
        viewportScale: SHARED_VIEWPORT_SCALE,
        canvas: SHARED_CANVAS,
    },
    scene: {
        key: 'scene',
        // 带整张场景图的立绘：沿用 Flutter 版更稳定的场景参数，
        // 宽度稍微放开一点，让横向构图更容易完整贴住屏幕。
        visibleWidthRatio: 1.08,
        visibleHeightRatio: 0.94,
        backgroundFitMode: 'full',
        viewportScale: SHARED_VIEWPORT_SCALE,
        canvas: SHARED_CANVAS,
    },
    contain: {
        key: 'contain',
        visibleWidthRatio: 1,
        visibleHeightRatio: 1,
        backgroundFitMode: 'contain',
        viewportScale: SHARED_VIEWPORT_SCALE,
        canvas: SHARED_CANVAS,
    },
};

function hasBackground(stage) {
    if (Array.isArray(stage && stage.backgroundPaths) && stage.backgroundPaths.length > 0) {
        return true;
    }

    return Boolean(
        stage &&
        Array.isArray(stage.layers) &&
        stage.layers.some((layer) => {
            if (
                !layer ||
                (
                    layer.isBackgroundLayer !== true &&
                    layer.isStaticImageLayer !== true &&
                    !layer.imagePath &&
                    !layer.staticImagePath
                )
            ) {
                return false;
            }
            return (
                Boolean(layer.imagePath || layer.staticImagePath) ||
                (Array.isArray(layer.backgroundTexturePaths) && layer.backgroundTexturePaths.length > 0) ||
                (Array.isArray(layer.texturePaths) && layer.texturePaths.length > 0)
            );
        }),
    );
}

function numberOrDefault(value, fallback) {
    return typeof value === 'number' && isFinite(value) ? value : fallback;
}

function firstString(values, fallback) {
    const matched = values.find((value) => typeof value === 'string' && value.trim());
    return matched ? matched.trim() : fallback;
}

function normalizeDisplayAlign(value) {
    const rawValue = typeof value === 'string'
        ? value.trim()
        : DEFAULT_STAGE_DISPLAY_ADJUSTMENT.displayAlign;
    const normalized = rawValue
        .replace(/[\s_-]+/g, '')
        .toLowerCase();
    const aliases = {
        center: 'center',
        middle: 'center',
        centre: 'center',
        top: 'top',
        bottom: 'bottom',
        left: 'left',
        right: 'right',
        topleft: 'topLeft',
        lefttop: 'topLeft',
        topright: 'topRight',
        righttop: 'topRight',
        bottomleft: 'bottomLeft',
        leftbottom: 'bottomLeft',
        bottomright: 'bottomRight',
        rightbottom: 'bottomRight',
    };
    return aliases[normalized] || DEFAULT_STAGE_DISPLAY_ADJUSTMENT.displayAlign;
}

function resolveReferenceViewport(adjustment) {
    const viewport = adjustment && adjustment.referenceViewport;
    return {
        width: Math.max(
            numberOrDefault(viewport && viewport.width, DEFAULT_DISPLAY_REFERENCE_VIEWPORT.width),
            1,
        ),
        height: Math.max(
            numberOrDefault(viewport && viewport.height, DEFAULT_DISPLAY_REFERENCE_VIEWPORT.height),
            1,
        ),
    };
}

function resolveStageDisplayAdjustment(stage) {
    const candidates = [
        stage && stage.folder,
        stage && stage.stageName,
        stage && stage.stageKey,
    ].filter(Boolean);

    const matchedKey = candidates.find((key) => (
        Object.prototype.hasOwnProperty.call(STAGE_DISPLAY_ADJUSTMENTS, key)
    ));
    const adjustment = matchedKey
        ? STAGE_DISPLAY_ADJUSTMENTS[matchedKey]
        : DEFAULT_STAGE_DISPLAY_ADJUSTMENT;
    const explicitAdjustment = matchedKey ? adjustment : null;
    const bounds = resolveStageFitBoundsRecord(stage);
    const displayAlign = firstString(
        [
            explicitAdjustment && explicitAdjustment.displayAlign,
            explicitAdjustment && explicitAdjustment.align,
            explicitAdjustment && explicitAdjustment.anchor,
            stage && stage.displayAlign,
            stage && stage.align,
            stage && stage.anchor,
            bounds && bounds.displayAlign,
            bounds && bounds.align,
            bounds && bounds.anchor,
        ],
        DEFAULT_STAGE_DISPLAY_ADJUSTMENT.displayAlign,
    );

    return {
        scale: Math.max(
            numberOrDefault(adjustment.scale, DEFAULT_STAGE_DISPLAY_ADJUSTMENT.scale),
            0.000001,
        ),
        displayAlign: normalizeDisplayAlign(displayAlign),
        offsetX: numberOrDefault(
            adjustment.offsetX,
            DEFAULT_STAGE_DISPLAY_ADJUSTMENT.offsetX,
        ),
        offsetY: numberOrDefault(
            adjustment.offsetY,
            DEFAULT_STAGE_DISPLAY_ADJUSTMENT.offsetY,
        ),
        responsive: adjustment.responsive !== false,
        referenceViewport: resolveReferenceViewport(adjustment),
    };
}

function isValidBounds(bounds) {
    return Boolean(
        bounds &&
        typeof bounds.x === 'number' && isFinite(bounds.x) &&
        typeof bounds.y === 'number' && isFinite(bounds.y) &&
        typeof bounds.width === 'number' && isFinite(bounds.width) && bounds.width > 0 &&
        typeof bounds.height === 'number' && isFinite(bounds.height) && bounds.height > 0,
    );
}

function resolveStageFitBoundsRecord(stage) {
    const candidates = [
        stage && stage.folder,
        stage && stage.stageName,
        stage && stage.stageKey,
    ].filter(Boolean);
    const matchedKey = candidates.find((key) => (
        Object.prototype.hasOwnProperty.call(STAGE_FIT_BOUNDS, key)
    ));
    return matchedKey ? STAGE_FIT_BOUNDS[matchedKey] : null;
}

function resolveStageFitBounds(stage) {
    const bounds = resolveStageFitBoundsRecord(stage);

    if (!isValidBounds(bounds)) {
        return null;
    }

    return {
        x: bounds.x,
        y: bounds.y,
        width: bounds.width,
        height: bounds.height,
        paddingX: numberOrDefault(bounds.paddingX, 0),
        paddingY: numberOrDefault(bounds.paddingY, 0),
    };
}

function resolveBoundsFitProfile(stage) {
    const bounds = resolveStageFitBoundsRecord(stage);
    const mode = typeof (bounds && bounds.backgroundFitMode) === 'string'
        ? bounds.backgroundFitMode.trim()
        : '';

    if (!mode) {
        return null;
    }

    if (Object.prototype.hasOwnProperty.call(STAGE_FIT_PROFILES, mode)) {
        return STAGE_FIT_PROFILES[mode];
    }

    const matchedProfileKey = Object.keys(STAGE_FIT_PROFILES).find((profileKey) => (
        STAGE_FIT_PROFILES[profileKey].backgroundFitMode === mode
    ));
    return matchedProfileKey ? STAGE_FIT_PROFILES[matchedProfileKey] : null;
}

export function resolveStageFitProfile(stage) {
    const boundsProfile = resolveBoundsFitProfile(stage);
    if (boundsProfile) {
        return boundsProfile;
    }

    // allowSceneSized 是我们从资源清单里继承过来的标记，
    // 它通常意味着这套立绘带有更完整的场景背景，需要更偏向横向铺满。
    const useSceneProfile = Boolean(stage && stage.allowSceneSized) || hasBackground(stage);
    return useSceneProfile
        ? STAGE_FIT_PROFILES.scene
        : STAGE_FIT_PROFILES.character;
}

export function buildStageFitConfig(stage) {
    const profile = resolveStageFitProfile(stage);
    const displayAdjustment = resolveStageDisplayAdjustment(stage);
    const fitBounds = resolveStageFitBounds(stage);
    return {
        profileKey: profile.key,
        visibleWidthRatio: profile.visibleWidthRatio,
        visibleHeightRatio: profile.visibleHeightRatio,
        backgroundFitMode: profile.backgroundFitMode,
        viewportScaleMin: profile.viewportScale.min,
        viewportScaleMax: profile.viewportScale.max,
        maxCanvasPixelRatio: profile.canvas.maxPixelRatio,
        displayScale: displayAdjustment.scale,
        displayAlign: displayAdjustment.displayAlign,
        displayOffsetX: displayAdjustment.offsetX,
        displayOffsetY: displayAdjustment.offsetY,
        displayOffsetResponsive: displayAdjustment.responsive,
        displayReferenceViewportWidth: displayAdjustment.referenceViewport.width,
        displayReferenceViewportHeight: displayAdjustment.referenceViewport.height,
        fitBounds,
    };
}
