<template>
  <div class="character-strip-shell">
    <div class="character-strip">
      <button
        v-for="(character, index) in characters"
        :key="character.cardId"
        type="button"
        class="character-tile"
        :class="{ 'character-tile--selected': index === selectedIndex }"
        @click="$emit('select-character', index)"
      >
        <img
          v-show="character.portraitPath"
          :src="portraitUrl(character)"
          class="character-tile__image"
          :alt="character.nameCn || character.name"
        >
        <div class="character-tile__label">
          {{ character.nameCn || character.name }}
        </div>
      </button>
    </div>
  </div>
</template>

<script>
import { toGalleryAssetUrl } from './assetPaths';

export default {
  name: 'CharacterStrip',
  props: {
    characters: {
      type: Array,
      required: true,
    },
    selectedIndex: {
      type: Number,
      required: true,
    },
  },
  emits: ['select-character'],
  methods: {
    portraitUrl(character) {
      return character && character.portraitPath
        ? toGalleryAssetUrl(character.portraitPath)
        : '';
    },
  },
};
</script>

