<template>
  <div
    ref="root"
    :class="[
      'stage-background',
      { 'stage-background--transparent': !showBase },
    ]"
  >
    <img
      v-if="basePath"
      ref="baseImage"
      :src="basePath"
      :class="[
        'stage-background__base',
        `stage-background__base--${fitMode}`,
        { 'stage-background__base--hidden': !showBase },
      ]"
      alt=""
      @load="handleBaseLoaded"
    >
    <div
      v-if="basePath && overlayItems.length"
      class="stage-background__overlay-plane"
      :style="overlayPlaneStyle"
    >
      <img
        v-for="overlay in overlayItems"
        :key="overlay.path"
        :src="overlay.path"
        class="stage-background__overlay"
        :style="overlayStyle(overlay)"
        alt=""
      >
    </div>
  </div>
</template>

<script>
export default {
  name: 'CharacterStageBackground',
  props: {
    backgroundPaths: {
      type: Array,
      default: () => [],
    },
    fitMode: {
      type: String,
      default: 'cover',
    },
    backgroundOverlays: {
      type: Array,
      default: () => [],
    },
    showBase: {
      type: Boolean,
      default: true,
    },
  },
  data() {
    return {
      baseNaturalWidth: 0,
      baseNaturalHeight: 0,
      stageWidth: 0,
      stageHeight: 0,
      resizeObserver: null,
    };
  },
  computed: {
    basePath() {
      return this.backgroundPaths.length ? this.backgroundPaths[0] : null;
    },
    overlayPaths() {
      return this.backgroundPaths.slice(1);
    },
    overlayItems() {
      if (this.backgroundOverlays.length) {
        return this.backgroundOverlays;
      }
      return this.overlayPaths.map((path) => ({ path }));
    },
    overlayPlaneStyle() {
      const baseWidth = this.baseNaturalWidth;
      const baseHeight = this.baseNaturalHeight;
      const stageWidth = this.stageWidth;
      const stageHeight = this.stageHeight;

      if (!baseWidth || !baseHeight || !stageWidth || !stageHeight) {
        return {};
      }

      const scaleX = stageWidth / baseWidth;
      const scaleY = stageHeight / baseHeight;
      const scale = this.fitMode === 'contain'
        ? Math.min(scaleX, scaleY)
        : Math.max(scaleX, scaleY);

      return {
        width: `${baseWidth}px`,
        height: `${baseHeight}px`,
        transform: `translate(-50%, -50%) scale(${scale})`,
      };
    },
  },
  watch: {
    basePath() {
      this.baseNaturalWidth = 0;
      this.baseNaturalHeight = 0;
      this.$nextTick(() => {
        this.handleBaseLoaded();
        this.updateStageSize();
      });
    },
  },
  mounted() {
    this.updateStageSize();
    this.handleBaseLoaded();
    if (typeof ResizeObserver === 'function') {
      this.resizeObserver = new ResizeObserver(() => {
        this.updateStageSize();
      });
      this.resizeObserver.observe(this.$refs.root);
      return;
    }
    window.addEventListener('resize', this.updateStageSize);
  },
  beforeDestroy() {
    if (this.resizeObserver) {
      this.resizeObserver.disconnect();
      this.resizeObserver = null;
      return;
    }
    window.removeEventListener('resize', this.updateStageSize);
  },
  methods: {
    handleBaseLoaded() {
      const image = this.$refs.baseImage;
      if (!image || !image.naturalWidth || !image.naturalHeight) {
        return;
      }
      this.baseNaturalWidth = image.naturalWidth;
      this.baseNaturalHeight = image.naturalHeight;
    },
    updateStageSize() {
      const root = this.$refs.root;
      if (!root) {
        return;
      }
      const rect = root.getBoundingClientRect();
      this.stageWidth = Math.max(rect.width, 1);
      this.stageHeight = Math.max(rect.height, 1);
    },
    overlayStyle(overlay) {
      if (
        typeof overlay.x !== 'number' ||
        typeof overlay.y !== 'number' ||
        !isFinite(overlay.x) ||
        !isFinite(overlay.y)
      ) {
        return {};
      }

      const style = {
        left: `${overlay.x}px`,
        top: `${overlay.y}px`,
        transform: 'none',
      };
      if (typeof overlay.width === 'number' && isFinite(overlay.width) && overlay.width > 0) {
        style.width = `${overlay.width}px`;
      }
      if (typeof overlay.height === 'number' && isFinite(overlay.height) && overlay.height > 0) {
        style.height = `${overlay.height}px`;
      }
      return style;
    },
  },
};
</script>

<style scoped>
.stage-background {
  position: absolute;
  inset: 0;
  background: #080b12;
  overflow: hidden;
}

.stage-background--transparent {
  background: transparent;
}

.stage-background__base,
.stage-background__overlay-plane {
  position: absolute;
  user-select: none;
  pointer-events: none;
}

.stage-background__base {
  inset: 0;
  width: 100%;
  height: 100%;
}

.stage-background__base--hidden {
  opacity: 0;
}

.stage-background__base--cover {
  /* 静态 PNG 背景始终铺满舞台，避免横屏页面出现留白。 */
  object-fit: cover;
  object-position: center center;
}

.stage-background__base--contain {
  /* fitMode 仍由上层保留，但静态背景展示统一以铺满页面为准。 */
  /*object-fit: cover;*/
  /*object-position: center center;*/

  object-fit: contain;
  object-position: center center;
}

.stage-background__base--full {
  object-fit: cover;
  object-position: center center;
}

.stage-background__overlay-plane {
  left: 50%;
  top: 50%;
  overflow: visible;
  transform-origin: center center;
}

.stage-background__overlay {
  /* 叠加裁片使用主背景坐标系的缩放，不再各自拉伸到整屏。 */
  position: absolute;
  left: 50%;
  top: 50%;
  width: auto;
  height: auto;
  max-width: none;
  max-height: none;
  transform: translate(-50%, -50%);
  user-select: none;
  pointer-events: none;
}
</style>
