  components: {
    CharacterStage,
    CharacterStrip,
  },
  props: {
    characters: {
      type: Array,
      required: true,
    },
    selectedIndex: {
      type: Number,
      required: true,
    },
    selectedStageIndex: {
      type: Number,
      default: 0,
