    embedMode: {
      type: Boolean,
      default: false,
    },
  },
  emits: ['select-character', 'select-stage'],
  data() {
    return {
      stripVisible: true,
    };
  },
  methods: {
    toggleStrip() {
      this.stripVisible = !this.stripVisible;
