<template>
  <div ref="container" class="spine-stage-frame">
    <div class="spine-stage-frame__surface">
      <iframe
        ref="frame"
        class="spine-stage-frame__frame"
        title="Spine Player"
        :src="frameSrc"
        allowtransparency="true"
      />
    </div>
    <div v-if="loading" class="spine-stage-frame__loading">立绘加载中...</div>
    <div v-if="error" class="spine-stage-frame__error">{{ error }}</div>
  </div>
</template>

<script>
import { resolveGalleryAssetPaths, toGalleryAssetUrl } from './assetPaths';
import { buildStageFitConfig } from './stageFitProfiles';

export default {
  name: 'SpineStageFrame',
  props: {
    entry: {
      type: Object,
      required: true,
    },
    stage: {
      type: Object,
      required: true,
    },
  },
  emits: ['failed'],
  data() {
    return {
      loading: true,
      error: '',
      viewportWidth: 0,
      viewportHeight: 0,
      resizeObserver: null,
      bootPending: false,
      frameBooted: false,
      activeRequestId: '',
      frameLoadToken: 0,
      lastReportedScale: 1,
    };
  },
  computed: {
    frameSrc() {
      // 给 public 下的 iframe 播放器带一个稳定版本号，
      // 避免浏览器把旧的 player.html 缓存在本地，导致适配逻辑看起来没有更新。
      // 同时把当前 stageKey 放进地址。立绘 1/2 切换时即使浏览器复用 iframe，
      // 也会被视为不同页面，播放器内部状态会完整重建。
      const stageKey = this.stage && this.stage.stageKey
        ? encodeURIComponent(this.stage.stageKey)
        : 'empty';
      return `${toGalleryAssetUrl('/gallery-assets/spine_player/player.html')}?v=spine-embed-api-20260612-skin-merge&stage=${stageKey}`;
    },
    fitConfig() {
      return buildStageFitConfig(this.stage);
    },
  },
  watch: {
    'stage.stageKey': {
      immediate: true,
      handler() {
        this.loading = true;
        this.error = '';
        this.frameBooted = false;
        this.lastReportedScale = 1;
        this.requestStageLoad();
      },
    },
    viewportWidth() {
      this.requestStageLoad();
    },
    viewportHeight() {
      this.requestStageLoad();
    },
  },
  mounted() {
    window.addEventListener('message', this.handlePlayerMessage);
    this.observeViewport();
    const frame = this.$refs.frame;
    if (frame) {
      frame.addEventListener('load', this.handleFrameLoad);
    }
  },
  beforeDestroy() {
    window.removeEventListener('message', this.handlePlayerMessage);
    const frame = this.$refs.frame;
    if (frame) {
      frame.removeEventListener('load', this.handleFrameLoad);
    }
    if (this.resizeObserver) {
      this.resizeObserver.disconnect();
    }
  },
  methods: {
    observeViewport() {
      const container = this.$refs.container;
      if (!container) {
        return;
      }

      const updateSize = () => {
        const rect = container.getBoundingClientRect();
        this.viewportWidth = Math.max(Math.round(rect.width), 0);
        this.viewportHeight = Math.max(Math.round(rect.height), 0);
      };

      updateSize();

      if (typeof ResizeObserver === 'undefined') {
        return;
      }

      this.resizeObserver = new ResizeObserver((entries) => {
        const entry = entries[0];
        if (!entry) {
          return;
        }
        const nextWidth = Math.max(Math.round(entry.contentRect.width), 0);
        const nextHeight = Math.max(Math.round(entry.contentRect.height), 0);
        if (nextWidth === this.viewportWidth && nextHeight === this.viewportHeight) {
          return;
        }
        this.viewportWidth = nextWidth;
        this.viewportHeight = nextHeight;
      });
      this.resizeObserver.observe(container);
    },
    currentViewportSize() {
      return {
        width: Math.max(this.viewportWidth, 1),
        height: Math.max(this.viewportHeight, 1),
      };
    },
    handleFrameLoad() {
      this.frameBooted = false;
      this.frameLoadToken += 1;
      this.loading = true;
      this.error = '';
      this.lastReportedScale = 1;
    },
    requestStageLoad() {
      if (!this.stage || !this.viewportWidth || !this.viewportHeight) {
        return;
      }
      if (this.bootPending) {
        return;
      }
      this.bootPending = true;
      this.$nextTick(() => {
        this.bootPending = false;
        if (!this.frameBooted) {
          return;
        }
        this.postStageToPlayer();
      });
    },
    postStageToPlayer() {
      const frame = this.$refs.frame;
      const targetWindow = frame && frame.contentWindow;
      if (!targetWindow || !this.stage) {
        return;
      }

      this.activeRequestId = [
        this.entry.cardId,
        this.stage.stageKey,
        this.viewportWidth,
        this.viewportHeight,
        Date.now(),
      ].join(':');

      this.loading = true;
      this.error = '';
      this.lastReportedScale = 1;

      targetWindow.postMessage(
        {
          type: 'load-stage',
          requestId: this.activeRequestId,
          payload: {
            stage: resolveGalleryAssetPaths(this.stage, true),
            fitConfig: this.fitConfig,
            viewport: this.currentViewportSize(),
          },
        },
        '*',
      );
    },
    handlePlayerMessage(event) {
      const frame = this.$refs.frame;
      if (!frame || event.source !== frame.contentWindow) {
        return;
      }

      const data = event.data || {};
      if (data.source !== 'spine-player') {
        return;
      }

      if (data.type === 'booted') {
        this.frameBooted = true;
        this.requestStageLoad();
        return;
      }

      if (data.type === 'fit-scale') {
        const payload = data.payload || {};
        if (typeof payload.scale === 'number' && isFinite(payload.scale)) {
          // 这里只记录 player.html 里实际算出来的 initial-scale，
          // Vue 外层不再额外参与缩放，避免和 iframe 内的适配逻辑互相叠加。
          const minScale = this.fitConfig.viewportScaleMin || 0.000001;
          const maxScale = this.fitConfig.viewportScaleMax || 1;
          this.lastReportedScale = Math.max(minScale, Math.min(maxScale, payload.scale));
          console.debug('[SpineStageFrame] fit-scale', {
            stageKey: this.stage && this.stage.stageKey,
            scale: this.lastReportedScale,
            payload,
          });
        }
        return;
      }

      if (data.type === 'log') {
        const payload = data.payload || {};
        if (
          payload.event === 'layer-drag-offset' ||
          payload.event === 'role-drag-offset'
        ) {
          console.log('[SpineStageFrame] layer drag offset', payload);
          return;
        }
        console.debug('[SpineStageFrame]', payload);
        return;
      }

      if (data.requestId && this.activeRequestId && data.requestId !== this.activeRequestId) {
        return;
      }

      if (data.type === 'ready') {
        this.loading = false;
        this.error = '';
        return;
      }

      if (data.type === 'error') {
        const payload = data.payload || {};
        this.loading = false;
        this.error = payload.message || '当前立绘无法播放';
        this.$emit('failed', this.stage.stageKey);
      }
    },
  },
};
</script>

<style scoped>
.spine-stage-frame {
  position: absolute;
  inset: 0;
  overflow: hidden;
}

.spine-stage-frame__surface {
  position: absolute;
  inset: 0;
}

.spine-stage-frame__frame {
  width: 100%;
  height: 100%;
  border: 0;
  display: block;
  background: transparent;
}

.spine-stage-frame__loading,
.spine-stage-frame__error {
  position: absolute;
  inset: auto 50% 22%;
  transform: translateX(-50%);
  min-width: 160px;
  padding: 10px 16px;
  border-radius: 14px;
  background: rgba(11, 16, 24, 0.78);
  color: rgba(255, 255, 255, 0.92);
  font-size: 14px;
  text-align: center;
  backdrop-filter: blur(8px);
  pointer-events: none;
}

.spine-stage-frame__error {
  background: rgba(145, 29, 42, 0.82);
}
</style>
