<template>
  <main
    class="gallery-page"
    :class="{ 'gallery-page--embed': embedMode }"
  >
    <div v-if="loading" class="gallery-page__message">角色资源加载中...</div>
    <div v-else-if="error" class="gallery-page__message gallery-page__message--error">
      {{ error }}
    </div>
    <CharacterGalleryScene
      v-else-if="selectedCharacter"
      :embed-mode="embedMode"
      :characters="characters"
      :selected-index="selectedIndex"
      :selected-stage-index="selectedStageIndex"
      :selected-character="selectedCharacter"
      @select-character="handleSelectCharacter"
      @select-stage="handleSelectStage"
    />
    <div v-else class="gallery-page__message">没有找到可展示的角色资源</div>
  </main>
</template>

<script>
import CharacterGalleryScene from '../components/gallery/CharacterGalleryScene.vue';
import { toGalleryAssetUrl } from '../components/gallery/assetPaths';

function parseBoolean(value) {
  if (typeof value === 'boolean') {
    return value;
  }
  if (value === null || typeof value === 'undefined') {
    return null;
  }
  const text = String(value).trim().toLowerCase();
  if (['1', 'true', 'yes', 'y', 'on', 'embed', 'player'].includes(text)) {
    return true;
  }
  if (['0', 'false', 'no', 'n', 'off', 'gallery'].includes(text)) {
    return false;
  }
  return null;
}

function parseInteger(value) {
  if (typeof value === 'number' && isFinite(value)) {
    return Math.trunc(value);
  }
  if (typeof value !== 'string' || !value.trim()) {
    return null;
  }
  const parsed = Number(value);
  return Number.isFinite(parsed) ? Math.trunc(parsed) : null;
}

function routeOptions() {
  if (typeof window === 'undefined' || !window.location) {
    return {};
  }
  const params = new URLSearchParams(window.location.search);
  return {
    mode: params.get('mode'),
    embed: params.get('embed'),
    showChrome: params.get('showChrome') || params.get('chrome'),
    cardId: params.get('cardId'),
    characterIndex: params.get('characterIndex'),
    stageIndex: params.get('stageIndex'),
    stageNo: params.get('stageNo') || params.get('stageNumber') || params.get('stage'),
    folder: params.get('folder'),
    stageKey: params.get('stageKey'),
    stageName: params.get('stageName'),
  };
}

export default {
  name: 'CharacterGalleryPage',
  components: {
    CharacterGalleryScene,
  },
  data() {
    return {
      loading: true,
      error: '',
      characters: [],
      selectedIndex: 0,
      selectedStageIndex: 0,
      embedMode: false,
      pendingExternalLoad: null,
    };
  },
  computed: {
    selectedCharacter() {
      if (!this.characters.length) {
        return null;
      }
      const safeIndex = Math.min(
        Math.max(this.selectedIndex, 0),
        this.characters.length - 1,
      );
      return this.characters[safeIndex] || null;
    },
  },
  async created() {
    this.applyChromeOptions(routeOptions());
    try {
      const response = await fetch(toGalleryAssetUrl('/gallery-assets/manifest.json'));
      if (!response.ok) {
        throw new Error('画廊资源清单加载失败。');
      }

      const manifest = await response.json();
      this.characters = Array.isArray(manifest.characters)
        ? manifest.characters
        : [];
      this.applyPlayerOptions(routeOptions(), { silent: true });
    } catch (error) {
      this.error = error && error.message ? error.message : '角色资源加载失败。';
      this.postPlayerEvent('error', { message: this.error });
    } finally {
      this.loading = false;
      this.$nextTick(() => {
        this.postPlayerEvent('ready', this.currentPlayerState());
        this.flushPendingExternalLoad();
      });
    }
  },
  mounted() {
    this.installExternalApi();
  },
  beforeDestroy() {
    if (typeof window !== 'undefined' && window.EdenGalleryPlayer === this.externalApi) {
      delete window.EdenGalleryPlayer;
      delete window.__EDEN_GALLERY_PLAYER__;
      if (window.document && window.document.documentElement) {
        delete window.document.documentElement.dataset.edenGalleryPlayer;
      }
    }
  },
  methods: {
    installExternalApi() {
      if (typeof window === 'undefined') {
        return;
      }
      this.externalApi = {
        load: (options = {}) => this.loadExternal(options),
        loadStage: (options = {}) => this.loadExternal(options),
        setEmbedMode: (enabled) => {
          this.embedMode = Boolean(enabled);
          const state = this.currentPlayerState();
          this.postPlayerEvent('mode-change', state);
          return state;
        },
        getState: () => this.currentPlayerState(),
      };
      this.exposeExternalApi(this.externalApi);
      this.postPlayerEvent('api-ready', this.currentPlayerState());
    },
    exposeExternalApi(api) {
      try {
        Object.defineProperty(window, 'EdenGalleryPlayer', {
          configurable: true,
          writable: true,
          value: api,
        });
        Object.defineProperty(window, '__EDEN_GALLERY_PLAYER__', {
          configurable: true,
          writable: true,
          value: api,
        });
      } catch (error) {
        window.EdenGalleryPlayer = api;
        window.__EDEN_GALLERY_PLAYER__ = api;
      }
      if (window.document && window.document.documentElement) {
        window.document.documentElement.dataset.edenGalleryPlayer = 'ready';
      }
    },
    applyChromeOptions(options) {
      const mode = typeof options.mode === 'string' ? options.mode.toLowerCase() : '';
      if (mode === 'embed' || mode === 'player') {
        this.embedMode = true;
      }
      if (mode === 'gallery') {
        this.embedMode = false;
      }

      const embed = parseBoolean(options.embed);
      if (embed !== null) {
        this.embedMode = embed;
      }

      const showChrome = parseBoolean(options.showChrome);
      if (showChrome !== null) {
        this.embedMode = !showChrome;
      }
    },
    async loadExternal(options = {}) {
      if (this.loading) {
        return new Promise((resolve, reject) => {
          this.pendingExternalLoad = { options, resolve, reject };
        });
      }

      try {
        const state = this.applyPlayerOptions(options);
        await this.$nextTick();
        const nextState = this.currentPlayerState(state);
        this.postPlayerEvent('loaded', nextState);
        return nextState;
      } catch (error) {
        const message = error && error.message ? error.message : String(error || '立绘加载失败');
        this.postPlayerEvent('error', { message });
        throw error;
      }
    },
    flushPendingExternalLoad() {
      const pending = this.pendingExternalLoad;
      if (!pending) {
        return;
      }
      this.pendingExternalLoad = null;
      this.loadExternal(pending.options).then(pending.resolve, pending.reject);
    },
    applyPlayerOptions(options = {}, config = {}) {
      this.applyChromeOptions(options);
      if (!this.characters.length) {
        return this.currentPlayerState();
      }

      const nextCharacterIndex = this.resolveCharacterIndex(options);
      if (nextCharacterIndex < 0 || nextCharacterIndex >= this.characters.length) {
        if (config.silent) {
          return this.currentPlayerState();
        }
        throw new Error('没有找到指定角色。');
      }

      const nextCharacter = this.characters[nextCharacterIndex];
      const nextStageIndex = this.resolveStageIndex(nextCharacter, options);
      if (nextStageIndex < 0 || nextStageIndex >= nextCharacter.stages.length) {
        if (config.silent) {
          return this.currentPlayerState();
        }
        throw new Error('没有找到指定立绘。');
      }

      this.selectedIndex = nextCharacterIndex;
      this.selectedStageIndex = nextStageIndex;
      return this.currentPlayerState({
        character: nextCharacter,
        characterIndex: nextCharacterIndex,
        stageIndex: nextStageIndex,
      });
    },
    resolveCharacterIndex(options = {}) {
      const byCharacterIndex = parseInteger(options.characterIndex);
      if (byCharacterIndex !== null) {
        return byCharacterIndex;
      }

      const cardId = parseInteger(options.cardId);
      if (cardId !== null) {
        return this.characters.findIndex((character) => character.cardId === cardId);
      }

      return Math.min(Math.max(this.selectedIndex, 0), this.characters.length - 1);
    },
    resolveStageIndex(character, options = {}) {
      const stages = Array.isArray(character && character.stages) ? character.stages : [];
      if (!stages.length) {
        return -1;
      }

      const stageKey = typeof options.stageKey === 'string' ? options.stageKey : '';
      if (stageKey) {
        return stages.findIndex((stage) => stage.stageKey === stageKey);
      }

      const folder = typeof options.folder === 'string' ? options.folder : '';
      if (folder) {
        return stages.findIndex((stage) => stage.folder === folder);
      }

      const stageName = typeof options.stageName === 'string' ? options.stageName : '';
      if (stageName) {
        return stages.findIndex((stage) => stage.stageName === stageName);
      }

      const stageIndex = parseInteger(options.stageIndex);
      if (stageIndex !== null) {
        return stageIndex;
      }

      const stageNo = parseInteger(options.stageNo);
      if (stageNo !== null) {
        return stageNo - 1;
      }

      if (character === this.selectedCharacter) {
        return Math.min(Math.max(this.selectedStageIndex, 0), stages.length - 1);
      }
      return 0;
    },
    currentPlayerState(override = {}) {
      const character = override.character || this.selectedCharacter;
      const characterIndex = typeof override.characterIndex === 'number'
        ? override.characterIndex
        : this.selectedIndex;
      const stageIndex = typeof override.stageIndex === 'number'
        ? override.stageIndex
        : this.selectedStageIndex;
      const stage = character && Array.isArray(character.stages)
        ? character.stages[Math.min(Math.max(stageIndex, 0), character.stages.length - 1)]
        : null;

      return {
        embedMode: this.embedMode,
        loading: this.loading,
        error: this.error,
        characterIndex,
        cardId: character ? character.cardId : null,
        name: character ? character.name : '',
        nameCn: character ? character.nameCn : '',
        stageIndex,
        stageFolder: stage ? stage.folder : '',
        stageName: stage ? stage.stageName : '',
        stageKey: stage ? stage.stageKey : '',
      };
    },
    postPlayerEvent(type, payload = {}) {
      if (typeof window === 'undefined') {
        return;
      }
      const event = {
        source: 'eden-gallery-player',
        type,
        payload,
        state: this.currentPlayerState(),
      };
      const text = JSON.stringify(event);
      try {
        if (window.EdenGalleryBridge && typeof window.EdenGalleryBridge.postMessage === 'function') {
          window.EdenGalleryBridge.postMessage(text);
        }
      } catch (error) {
        console.warn('[EdenGalleryPlayer] bridge post failed', error);
      }
      try {
        if (
          window.flutter_inappwebview &&
          typeof window.flutter_inappwebview.callHandler === 'function'
        ) {
          window.flutter_inappwebview.callHandler('EdenGalleryPlayerEvent', event);
        }
      } catch (error) {
        console.warn('[EdenGalleryPlayer] inappwebview post failed', error);
      }
      try {
        window.parent && window.parent.postMessage(event, '*');
      } catch (error) {
        console.warn('[EdenGalleryPlayer] parent post failed', error);
      }
      window.dispatchEvent(new CustomEvent('eden-gallery-player', { detail: event }));
    },
    handleSelectCharacter(index) {
      this.selectedIndex = index;
      this.selectedStageIndex = 0;
      this.$nextTick(() => {
        this.postPlayerEvent('loaded', this.currentPlayerState());
      });
    },
    handleSelectStage(index) {
      this.selectedStageIndex = index;
      this.$nextTick(() => {
        this.postPlayerEvent('loaded', this.currentPlayerState());
      });
    },
  },
};
</script>

<style scoped>
.gallery-page {
  width: 100%;
  height: 100%;
  background: #080b12;
}

.gallery-page__message {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  padding: 24px;
  color: rgba(255, 255, 255, 0.92);
  font-size: 16px;
  text-align: center;
}

.gallery-page__message--error {
  color: #ffb0aa;
}
</style>
